const today = $now.setZone('Pacific/Auckland').toFormat('dd-MM-yyyy');

return $input.all().filter(item => {
  const dateStr = String(item.json.record_date);
  return dateStr === today;
});

const items = $input.all();
const todayWeekday = $now.setZone('Pacific/Auckland').weekday; // 1=Mon ~ 7=Sun

const hospitals = {
  'H-001': {
    name: 'Christchurch ENT Clinic',
    email: 'chchent@examples.com',
    audiologist: 'Daisy Song',
    workdays: [1, 2, 3, 4, 5],
    shift: 'AM'
  },
  'H-002': {
    name: 'Selwyn Hearing Centre',
    email: 'selwynhearing@examples.com',
    audiologist: 'Daisy Song',
    workdays: [1, 3, 5],
    shift: 'PM'
  },
  'H-003': {
    name: 'Canterbury Audiology Associates',
    email: 'Canterburyaa@examples.com',
    audiologist: 'Daisy Song',
    workdays: [2, 4],
    shift: 'PM'
  }
};

// Working on 'AM' 
const targetShift = 'PM';

const summary = {};
Object.entries(hospitals)
  .filter(([id, h]) => h.shift === targetShift && h.workdays.includes(todayWeekday))
  .forEach(([id, h]) => {
    summary[id] = {
      hospital_id:        id,
      hospital_name:      h.name,
      recipient_email:    h.email,
      audiologist:        h.audiologist,
      date:               $now.setZone('Pacific/Auckland').toFormat('dd-MM-yyyy'),
      new_consultations:  0,
      fittings_completed: 0,
      repairs_completed:  0,
      total_sales_nzd:    0,
      total_repair_nzd:   0
    };
  });

items.forEach(item => {
  const d   = item.json;
  const hid = d.hospital_id;
  if (!summary[hid]) return;

  if (d.transaction_type === 'New Consultation')  summary[hid].new_consultations++;
  if (d.transaction_type === 'Fitting Completed') summary[hid].fittings_completed++;
  if (d.transaction_type === 'Repair Completed')  summary[hid].repairs_completed++;
  summary[hid].total_sales_nzd  += Number(d.sale_price_nzd) || 0;
  summary[hid].total_repair_nzd += Number(d.repair_fee_nzd) || 0;
});

return Object.values(summary).map(s => ({ json: s }));
